    88	    private void usedIn(Class<?> cls, Map<Class<?>, Set<Class<?>>> usedIn) {
    89	        Set<Property> memorableProperties = new HashSet<>();
    90	
    91	        for (Property property : properties(crApiVersion, cls).values()) {
    92	            if (property.isAnnotationPresent(KubeLink.class)) {
    93	                continue;
    94	            }
    95	
    96	            memorableProperties.add(property);
    97	        }
    98	
    99	        for (Property property : memorableProperties) {
   100	            PropertyType propertyType = property.getType();
   101	            Class<?> type = propertyType.isArray() ? propertyType.arrayBase() : propertyType.getType();
   102	            for (Class<?> c : subtypesOrSelf(type)) {
   103	                if (Schema.isJsonScalarType(c)) {
   104	                    continue;
   105	                }
   106	
   107	                Set<Class<?>> classes = getOrCreateClassesSet(c, usedIn);
   108	
   109	                classes.add(cls);
   110	
   111	                usedIn(c, usedIn);
   112	            }
   113	        }
   114	    }
