   191	    /**
   192	     * Sets warning message for deprecated fields
   193	     *
   194	     * @param property  The property which will be checked for deprecation
   195	     *
   196	     * @throws IOException  Throws IOException when appending to the output fails
   197	     */
   198	    private void addDeprecationWarning(Property property) throws IOException {
   199	        DeprecatedProperty strimziDeprecated = property.getAnnotation(DeprecatedProperty.class);
   200	        Deprecated langDeprecated = property.getAnnotation(Deprecated.class);
   201	
   202	        if (strimziDeprecated != null || langDeprecated != null) {
   203	            if (strimziDeprecated == null || langDeprecated == null) {
   204	                err(property + " must be annotated with both @" + Deprecated.class.getName()
   205	                        + " and @" + DeprecatedPro<response clipped><NOTE>Due to the max output limit, only part of this file has been shown to you. You should retry this tool after you have searched inside the file with `grep -n` in order to find the line numbers of what you are looking for.</NOTE>ion, but file " + filename + " does not exist!");
   206	            }
   207	
   208	            out.append("xref:type-").append(cls.getSimpleName()).append("-schema-{context}[Full list of `").append(cls.getSimpleName()).append("` schema properties]").append(NL);
   209	            out.append(NL);
   210	            out.append("include::../" + filename + "[leveloffset=+1]").append(NL);
   211	            out.append(NL);
   212	            out.append("[id='type-").append(cls.getSimpleName()).append("-schema-{context}']").append(NL);
   213	            out.append("== `").append(cls.getSimpleName()).append("` schema properties").append(NL);
   214	            out.append(NL);
   215	
   216	        } else if (description != null) {
   217	            out.append(getDescription(description)).append(NL);
   218	        }
   219	        out.append(NL);
   220	    }
