   222	    private void appendUsedIn(Crd crd, Class<?> cls) throws IOException {
   223	        List<Class<?>> usedIn = new ArrayList<>(this.usedIn.getOrDefault(cls, emptySet()));
   224	        usedIn.sort(Comparator.comparing(c -> c.getSimpleName().toLowerCase(Locale.ENGLISH)));
   225	        if (!usedIn.isEmpty()) {
   226	            out.append("Used in: ");
   227	            boolean first = true;
   228	            for (Class<?> usingClass : usedIn) {
   229	                if (!first) {
   230	                    out.append(", ");
   231	                }
   232	                typeLink(crd, out, usingClass);
   233	                first = false;
   234	            }
   235	            out.append(NL);
   236	            out.append(NL);
   237	        }
   238	    }
