   240	    private void appendDiscriminator(Crd crd, Class<?> cls) throws IOException {
   241	        String discriminator = discriminator(cls.getSuperclass());
   242	        if (discriminator != null) {
   243	            if (cls.isAnnotationPresent(PresentInVersions.class)) {
   244	                // Adds a note about presence in different versions
   245	                out.append("The type ")
   246	                        .append(cls.getSimpleName())
   247	                        .append(" is supported only in the Strimzi API version(s) ")
   248	                        .append(ApiVersion.parseRange(cls.getAnnotation(PresentInVersions.class).value()).toString())
   249	                        .append(".")
   250	                        .append(NL)
   251	                        .append(NL);
   252	            }
   253	
   254	            String subtypeLinks = subtypes(crApiVersion, cls.getSuperclass()).stream().filter(c -> !c.equals(cls)).map(c -> {
   255	                try {
   256	                    return typeLink(crd, c);
   257	                } catch (IOException e) {
   258	                    throw new RuntimeException(e);
   259	                }
   260	            }).collect(Collectors.joining(", "));
   261	            out.append("The `").append(discriminator)
   262	                    .append("` property is a discriminator that distinguishes use of the `")
   263	                    .append(cls.getSimpleName()).append("` type from ");
   264	            if (subtypeLinks.trim().isEmpty()) {
   265	                out.append("other subtypes that may be added in the future.");
   266	            } else {
   267	                out.append(subtypeLinks).append(".");
   268	            }
   269	            out.append(NL);
   270	            out.append("It must have the value `").append(subtypeMap(cls.getSuperclass()).get(cls)).append("` for the type `").append(cls.getSimpleName()).append("`.").append(NL);
   271	        }
   272	    }
   273	
   274	    private void appendRepeated(char c, int num) throws IOException {
   275	        for (int i = 0; i < num; i++) {
   276	            out.append(c);
   277	        }
   278	    }
