   280	    public void typeLink(Crd crd, Appendable out, Class<?> cls) throws IOException {
   281	        if (short.class.equals(cls)
   282	                || Short.class.equals(cls)
   283	                || int.class.equals(cls)
   284	                || Integer.class.equals(cls)
   285	                || long.class.equals(cls)
   286	                || Long.class.equals(cls)) {
   287	            out.append("integer");
   288	        } else if (Float.class.equals(cls)
   289	                || float.class.equals(cls)
   290	                || Double.class.equals(cls)
   291	                || double.class.equals(cls)) {
   292	            out.append("number");
   293	        } else if (Object.class.equals(cls)
   294	                || String.class.equals(cls)
   295	                || Map.class.equals(cls)
   296	                || Boolean.class.equals(cls)
   297	                || boolean.class.equals(cls)) {
   298	            out.append(cls.getSimpleName().toLowerCase(Locale.ENGLISH));
   299	        } else if (isPolymorphic(cls)) {
   300	            out.append(subtypes(crApiVersion, cls).stream().map(c -> {
   301	                try {
   302	                    return typeLink(crd, c);
   303	                } catch (IOException e) {
   304	                    throw new RuntimeException(e);
   305	                }
   306	            }).collect(Collectors.joining(", ")));
   307	        } else {
   308	            out.append("xref:").append(anchor(cls)).append("[`").append(cls.getSimpleName()).append("`]");
   309	        }
   310	    }
   311	
   312	    public String typeLink(Crd crd, Class<?> cls) throws IOException {
   313	        StringBuilder sb = new StringBuilder();
   314	        typeLink(crd, sb, cls);
   315	        return sb.toString();
   316	    }
