   318	    public static void main(String[] args) throws IOException, ClassNotFoundException {
   319	        Linker linker = null;
   320	        File out = null;
   321	        List<Class<? extends CustomResource>> classes = new ArrayList<>();
   322	
   323	        for (int i = 0; i < args.length; i++) {
   324	            String arg = args[i];
   325	            if (arg.startsWith("-")) {
   326	                if ("--linker".equals(arg)) {
   327	                    String className = args[++i];
   328	                    Class<? extends Linker> linkerClass = classInherits(Class.forName(className), Linker.class);
   329	                    if (linkerClass != null) {
   330	                        try {
   331	                            linker = linkerClass.getConstructor(String.class).newInstance(args[++i]);
   332	                        } catch (ReflectiveOperationException e) {
   333	                            throw new RuntimeException("--linker option can't be handled", e);
   334	                        }
   335	                    } else {
   336	                        System.err.println(className + " is not a subclass of " + Linker.class.getName());
   337	                    }
   338	                } else {
   339	                    throw new RuntimeException("Unsupported option " + arg);
   340	                }
   341	            } else {
   342	                if (out == null) {
   343	                    out = new File(arg);
   344	                } else {
   345	                    // If we have fallen in the else branch here, the arg has to be a class name
   346	                    Class<? extends CustomResource> cls = classInherits(Class.forName(arg), CustomResource.class);
   347	                    if (cls != null) {
   348	                        classes.add(cls);
   349	                    } else {
   350	                        System.err.println(arg + " is not a subclass of " + CustomResource.class.getName());
   351	                    }
   352	                }
   353	            }
   354	        }
   355	
   356	        ApiVersion crApiVersion = ApiVersion.V1;
   357	
   358	        try (OutputStreamWriter writer = new OutputStreamWriter(new FileOutputStream(out), StandardCharsets.UTF_8)) {
   359	            writer.append(":_mod-docs-content-type: REFERENCE").append(NL).append(NL);
   360	            writer.append("// This file is auto-generated by ")
   361	                .append(DocGenerator.class.getName())
   362	                .append(".").append(NL);
   363	            writer.append("// To change this documentation you need to edit the Java sources.").append(NL);
   364	            writer.append(NL);
   365	            DocGenerator dg = new DocGenerator(crApiVersion, 1, classes, writer, linker);
   366	            for (Class<? extends CustomResource> c : classes) {
   367	                dg.generate(c);
   368	            }
   369	            if (dg.numErrors > 0) {
   370	                System.err.println("There were " + dg.numErrors + " errors");
   371	                System.exit(1);
   372	            }
   373	        }
   374	    }
