   376	    @SuppressWarnings("unchecked")
   377	    static <T> Class<? extends T> classInherits(Class<?> cls, Class<T> test) {
   378	        if (test.isAssignableFrom(cls)) {
   379	            return (Class<? extends T>) cls;
   380	        }
   381	        return null;
   382	    }
   383	}
